'use strict';

const path = require('path');

const {
  RESOURCE_ALLOWLIST,
  AGENT_ALLOWLIST,
  readResourceFromFilesystem,
  readAgentFromFilesystem,
} = require('../lib/mcp/content/runtime-content');

const SRC_ROOT = path.resolve(__dirname, '..');

function serializeModule(exportName, value, runtimeName) {
  return `'use strict';

// Generated by build-mcp-registry transform — do not edit.
// Source runtime: ${runtimeName}

const ${exportName} = Object.freeze(${JSON.stringify(value, null, 2)});

module.exports = {
  ${exportName},
};
`;
}

function buildResourceRegistry(runtime) {
  const registry = {};

  for (const id of Object.keys(RESOURCE_ALLOWLIST)) {
    const result = readResourceFromFilesystem(id, runtime, SRC_ROOT);
    if (result.error) {
      throw new Error(result.error);
    }
    registry[id] = result.content;
  }

  return serializeModule('RESOURCE_REGISTRY', registry, runtime.name);
}

function buildAgentRegistry(runtime) {
  const registry = {};

  for (const agentName of AGENT_ALLOWLIST) {
    const result = readAgentFromFilesystem(agentName, runtime, SRC_ROOT);
    if (result.error) {
      throw new Error(result.error);
    }
    registry[agentName] = result.agent;
  }

  return serializeModule('AGENT_REGISTRY', registry, runtime.name);
}

function buildMcpRegistry(_content, runtime, { param }) {
  if (param === 'resources') {
    return buildResourceRegistry(runtime);
  }

  if (param === 'agents') {
    return buildAgentRegistry(runtime);
  }

  throw new Error(`Unknown build-mcp-registry target: "${param}"`);
}

module.exports = buildMcpRegistry;
